mapper.insert:
INSERT INTO SHOP_CART (
    BOOK_NUM
    , CART_CNT
    , MEM_EMAIL
) VALUES (
    #{bookNum}
    , #{cartCnt}
    , #{memEmail}
)

mapper.select:
SELECT MEM_EMAIL
FROM SHOP_CART
WHERE BOOK_NUM = #{bookNum}
AND MEM_EMAIL = #{memEmail}

mapper.update:
UPDATE SHOP_CART
SET
    CART_CNT = CART_CNT + #{cartCnt}
    , CART_DATE = SYSDATE()
WHERE BOOK_NUM = #{bookNum}
AND MEM_EMAIL = #{memEmail}

